#include <stdio.h>
#include <string.h>
int main() {
    char s[101];
    scanf("%s", s);
    int count = 0;
    for (int i = 0; i < strlen(s) - 2; i++) {
        if (s[i] == 'Q' && s[i + 1] == 'A' && s[i + 2] == 'Q') {
            count++;
        }
    }
    printf("%d\n", count);
    return 0;
}

